/**
 * Unit tests for context-exhaustion-warner hook
 * Tests UserPromptSubmit hook that reads context window usage from temp file
 * and injects tiered warnings via additionalContext.
 *
 * CC 2.1.9 compliant with additionalContext injection
 */

import { describe, test, expect, beforeEach, vi } from 'vitest';
import type { HookInput } from '../../types.js';
import {
  contextExhaustionWarner,
  readContextPercentage,
  getContextPctFilePath,
  TIERS,
  _resetForTesting,
} from '../../prompt/context-exhaustion-warner.js';

// =============================================================================
// Mocks
// =============================================================================

vi.mock('node:fs', () => ({
  existsSync: vi.fn(),
  readFileSync: vi.fn(),
}));

import { existsSync, readFileSync } from 'node:fs';

const mockExistsSync = vi.mocked(existsSync);
const mockReadFileSync = vi.mocked(readFileSync);

// =============================================================================
// Test Utilities
// =============================================================================

function createPromptInput(prompt: string, overrides: Partial<HookInput> = {}): HookInput {
  return {
    hook_event: 'UserPromptSubmit',
    tool_name: 'UserPromptSubmit',
    session_id: 'test-session-abc',
    project_dir: '/test/project',
    tool_input: {},
    prompt,
    ...overrides,
  };
}

/**
 * Set up mocks so the temp file contains a given percentage string.
 */
function mockContextFile(content: string): void {
  mockExistsSync.mockReturnValue(true);
  mockReadFileSync.mockReturnValue(content);
}

/**
 * Set up mocks so the temp file does not exist.
 */
function mockNoContextFile(): void {
  mockExistsSync.mockReturnValue(false);
}

// =============================================================================
// Tests
// =============================================================================

describe('prompt/context-exhaustion-warner', () => {
  beforeEach(() => {
    _resetForTesting();
    vi.clearAllMocks();
  });

  // ---------------------------------------------------------------------------
  // readContextPercentage unit tests
  // ---------------------------------------------------------------------------

  describe('readContextPercentage', () => {
    test('returns null when temp file does not exist', () => {
      mockNoContextFile();
      expect(readContextPercentage('test-session')).toBeNull();
    });

    test('returns parsed integer when file contains valid percentage', () => {
      mockContextFile('75');
      expect(readContextPercentage('test-session')).toBe(75);
    });

    test('returns null for NaN content', () => {
      mockContextFile('not-a-number');
      expect(readContextPercentage('test-session')).toBeNull();
    });

    test('returns null for percentage > 100', () => {
      mockContextFile('150');
      expect(readContextPercentage('test-session')).toBeNull();
    });

    test('returns null for negative percentage', () => {
      mockContextFile('-5');
      expect(readContextPercentage('test-session')).toBeNull();
    });

    test('handles whitespace around value', () => {
      mockContextFile('  82  \n');
      expect(readContextPercentage('test-session')).toBe(82);
    });
  });

  // ---------------------------------------------------------------------------
  // getContextPctFilePath
  // ---------------------------------------------------------------------------

  describe('getContextPctFilePath', () => {
    test('returns /tmp/ork-ctx-pct-{sessionId}.txt', () => {
      expect(getContextPctFilePath('my-session')).toBe('/tmp/ork-ctx-pct-my-session.txt');
    });
  });

  // ---------------------------------------------------------------------------
  // TIERS constant
  // ---------------------------------------------------------------------------

  describe('TIERS', () => {
    test('are sorted descending by pct', () => {
      for (let i = 1; i < TIERS.length; i++) {
        expect(TIERS[i - 1].pct).toBeGreaterThan(TIERS[i].pct);
      }
    });

    test('has 3 tiers: CRITICAL, WARNING, NOTICE', () => {
      expect(TIERS.map(t => t.level)).toEqual(['CRITICAL', 'WARNING', 'NOTICE']);
    });
  });

  // ---------------------------------------------------------------------------
  // Hook: silent success cases
  // ---------------------------------------------------------------------------

  describe('silent success (no warning)', () => {
    test('returns silent success when no temp file exists', () => {
      mockNoContextFile();
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput).toBeUndefined();
    });

    test('returns silent success when pct < 70', () => {
      mockContextFile('55');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
      expect(result.hookSpecificOutput).toBeUndefined();
    });

    test('returns silent success when session_id is missing', () => {
      // Mock getSessionId to return empty string
      const input = createPromptInput('hello', { session_id: '' as any });
      // With empty session_id, getSessionId() fallback will be used,
      // but if the file doesn't exist for that session, still silent
      mockNoContextFile();
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Hook: tiered warnings
  // ---------------------------------------------------------------------------

  describe('tiered warnings', () => {
    test('returns NOTICE warning at exactly 70%', () => {
      mockContextFile('70');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context NOTICE]');
      expect(result.hookSpecificOutput?.additionalContext).toContain('70%');
    });

    test('returns WARNING at 80%', () => {
      mockContextFile('80');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context WARNING]');
      expect(result.hookSpecificOutput?.additionalContext).toContain('80%');
    });

    test('returns CRITICAL at 90%', () => {
      mockContextFile('90');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context CRITICAL]');
      expect(result.hookSpecificOutput?.additionalContext).toContain('90%');
    });

    test('returns CRITICAL at 95% (above 90 threshold)', () => {
      mockContextFile('95');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context CRITICAL]');
      expect(result.hookSpecificOutput?.additionalContext).toContain('95%');
    });

    test('returns WARNING at 85% (between 80 and 90)', () => {
      mockContextFile('85');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context WARNING]');
      expect(result.hookSpecificOutput?.additionalContext).toContain('85%');
    });

    test('returns NOTICE at 75% (between 70 and 80)', () => {
      mockContextFile('75');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context NOTICE]');
      expect(result.hookSpecificOutput?.additionalContext).toContain('75%');
    });
  });

  // ---------------------------------------------------------------------------
  // Hook: escalation-only behavior (no repeat warnings)
  // ---------------------------------------------------------------------------

  describe('escalation-only (no repeat warnings)', () => {
    test('does NOT repeat same tier warning', () => {
      mockContextFile('75');
      const input = createPromptInput('hello');

      // First call: should warn
      const result1 = contextExhaustionWarner(input);
      expect(result1.hookSpecificOutput?.additionalContext).toContain('[Context NOTICE]');

      // Second call at same tier: should be silent
      const result2 = contextExhaustionWarner(input);
      expect(result2.continue).toBe(true);
      expect(result2.suppressOutput).toBe(true);
      expect(result2.hookSpecificOutput).toBeUndefined();
    });

    test('escalates from NOTICE (70) to WARNING (80)', () => {
      const input = createPromptInput('hello');

      // First: 70% NOTICE
      mockContextFile('72');
      const result1 = contextExhaustionWarner(input);
      expect(result1.hookSpecificOutput?.additionalContext).toContain('[Context NOTICE]');

      // Second: 82% WARNING (escalation)
      mockContextFile('82');
      const result2 = contextExhaustionWarner(input);
      expect(result2.hookSpecificOutput?.additionalContext).toContain('[Context WARNING]');
    });

    test('escalates from WARNING (80) to CRITICAL (90)', () => {
      const input = createPromptInput('hello');

      // First: 80% WARNING
      mockContextFile('80');
      const result1 = contextExhaustionWarner(input);
      expect(result1.hookSpecificOutput?.additionalContext).toContain('[Context WARNING]');

      // Second: 92% CRITICAL (escalation)
      mockContextFile('92');
      const result2 = contextExhaustionWarner(input);
      expect(result2.hookSpecificOutput?.additionalContext).toContain('[Context CRITICAL]');
    });

    test('does not warn again after reaching CRITICAL even at 100%', () => {
      const input = createPromptInput('hello');

      // First: 90% CRITICAL
      mockContextFile('90');
      const result1 = contextExhaustionWarner(input);
      expect(result1.hookSpecificOutput?.additionalContext).toContain('[Context CRITICAL]');

      // Second: still at 95% — already warned at CRITICAL tier
      mockContextFile('95');
      const result2 = contextExhaustionWarner(input);
      expect(result2.suppressOutput).toBe(true);
      expect(result2.hookSpecificOutput).toBeUndefined();
    });
  });

  // ---------------------------------------------------------------------------
  // Hook: reset after context drop
  // ---------------------------------------------------------------------------

  describe('reset after context drop', () => {
    test('resets warnings when pct drops below 70 (after /compact)', () => {
      const input = createPromptInput('hello');

      // First: 80% WARNING
      mockContextFile('80');
      const result1 = contextExhaustionWarner(input);
      expect(result1.hookSpecificOutput?.additionalContext).toContain('[Context WARNING]');

      // Drop to 40% (simulating /compact)
      mockContextFile('40');
      const result2 = contextExhaustionWarner(input);
      expect(result2.suppressOutput).toBe(true);
      expect(result2.hookSpecificOutput).toBeUndefined();

      // Back to 75% — should warn again (NOTICE)
      mockContextFile('75');
      const result3 = contextExhaustionWarner(input);
      expect(result3.hookSpecificOutput?.additionalContext).toContain('[Context NOTICE]');
    });

    test('after reset, re-warns on next escalation', () => {
      const input = createPromptInput('hello');

      // Hit CRITICAL
      mockContextFile('92');
      contextExhaustionWarner(input);

      // Drop below 70 (reset)
      mockContextFile('30');
      contextExhaustionWarner(input);

      // Back up to 70 — should warn NOTICE again
      mockContextFile('70');
      const result = contextExhaustionWarner(input);
      expect(result.hookSpecificOutput?.additionalContext).toContain('[Context NOTICE]');
    });
  });

  // ---------------------------------------------------------------------------
  // Hook: invalid file content edge cases
  // ---------------------------------------------------------------------------

  describe('invalid file content', () => {
    test('handles NaN file content gracefully', () => {
      mockContextFile('abc');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('handles pct > 100 gracefully', () => {
      mockContextFile('200');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('handles negative pct gracefully', () => {
      mockContextFile('-10');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });

    test('handles empty file content gracefully', () => {
      mockContextFile('');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      expect(result.continue).toBe(true);
      expect(result.suppressOutput).toBe(true);
    });
  });

  // ---------------------------------------------------------------------------
  // Hook: additionalContext format
  // ---------------------------------------------------------------------------

  describe('additionalContext format', () => {
    test('contains the right tier label in brackets', () => {
      mockContextFile('90');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toMatch(/^\[Context CRITICAL\]/);
    });

    test('contains current usage percentage', () => {
      mockContextFile('83');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toContain('(Current usage: 83%)');
    });

    test('contains actionable advice text', () => {
      mockContextFile('71');
      const input = createPromptInput('hello');
      const result = contextExhaustionWarner(input);

      const ctx = result.hookSpecificOutput?.additionalContext as string;
      expect(ctx).toContain('/ork:commit');
    });

    test('always continues execution (never blocks)', () => {
      for (const pct of ['0', '50', '70', '80', '90', '100', 'abc', '-1', '200']) {
        _resetForTesting();
        vi.clearAllMocks();
        if (pct === '100' || pct === 'abc' || pct === '-1' || pct === '200') {
          // These are invalid and readContextPercentage returns null
          mockContextFile(pct);
        } else {
          mockContextFile(pct);
        }
        const input = createPromptInput('hello');
        const result = contextExhaustionWarner(input);
        expect(result.continue).toBe(true);
      }
    });
  });
});
